import json
import urllib.request

tickers = ['SPYM', 'SCHG', 'DYNF', 'CGGR', 'SPHQ', 'XLG', 'AIQ', 'SOXQ', 'PSI']
results = {}

for ticker in tickers:
    url = f"https://query2.finance.yahoo.com/v8/finance/chart/{ticker}?interval=1d&range=1d"
    try:
        req = urllib.request.Request(url, headers={'User-Agent': 'Mozilla/5.0'})
        with urllib.request.urlopen(req, timeout=10) as resp:
            data = json.loads(resp.read())
            meta = data['chart']['result'][0]['meta']
            results[ticker] = {
                'price': meta.get('regularMarketPrice', 'N/A'),
                'change': meta.get('regularMarketChangePercent', 'N/A')
            }
    except Exception as e:
        results[ticker] = {'price': 'N/A', 'change': 'N/A', 'error': str(e)}

for t, v in results.items():
    print(f"{t}: ${v['price']} ({v['change']}%)")
"}

